    // ========== CONVERSION METHOD ==========

    private AppointmentResponseDTO convertToDTO(Appointment appointment) {
        if (appointment == null) {
            return null;
        }

        AppointmentResponseDTO dto = new AppointmentResponseDTO();
        dto.setAppointmentId(appointment.getAppointmentId());
        dto.setStartDateTime(appointment.getStartDateTime());
        dto.setEndDateTime(appointment.getEndDateTime());
        dto.setStatus(appointment.getStatus());
        dto.setCaregiverPresence(appointment.getCaregiverPresence());
        dto.setVideoLink(appointment.getVideoLink());
        dto.setSimpleSummary(appointment.getSimpleSummary());
        dto.setDoctorNotes(appointment.getDoctorNotes());
        dto.setRecurring(appointment.getRecurring());
        dto.setCreatedAt(appointment.getCreatedAt());
        dto.setUpdatedAt(appointment.getUpdatedAt());

        // Convert patient (without circular references)
        if (appointment.getPatient() != null) {
            PatientSimpleDTO patientDTO = new PatientSimpleDTO();
            patientDTO.setUserId(appointment.getPatient().getUserId());
            patientDTO.setName(appointment.getPatient().getName());
            patientDTO.setEmail(appointment.getPatient().getEmail());
            patientDTO.setPhone(appointment.getPatient().getPhone());
            dto.setPatient(patientDTO);
        }

        // Convert doctor
        if (appointment.getDoctor() != null) {
            UserSimpleDTO doctorDTO = new UserSimpleDTO();
            doctorDTO.setUserId(appointment.getDoctor().getUserId());
            doctorDTO.setName(appointment.getDoctor().getName());
            doctorDTO.setEmail(appointment.getDoctor().getEmail());
            doctorDTO.setRole(appointment.getDoctor().getRole());
            dto.setDoctor(doctorDTO);
        }

        // Convert caregiver
        if (appointment.getCaregiver() != null) {
            UserSimpleDTO caregiverDTO = new UserSimpleDTO();
            caregiverDTO.setUserId(appointment.getCaregiver().getUserId());
            caregiverDTO.setName(appointment.getCaregiver().getName());
            caregiverDTO.setEmail(appointment.getCaregiver().getEmail());
            caregiverDTO.setRole(appointment.getCaregiver().getRole());
            dto.setCaregiver(caregiverDTO);
        }

        // Convert consultation type
        if (appointment.getConsultationType() != null) {
            ConsultationTypeSimpleDTO typeDTO = new ConsultationTypeSimpleDTO();
            typeDTO.setId(appointment.getConsultationType().getId());
            typeDTO.setName(appointment.getConsultationType().getName());
            typeDTO.setDuration(appointment.getConsultationType().getDuration());
            typeDTO.setDescription(appointment.getConsultationType().getDescription());
            dto.setConsultationType(typeDTO);
        }

        return dto;
    }
}

