    // ========== CREATE WITH DTO ==========

    @PostMapping
    public ResponseEntity<AppointmentResponseDTO> createAppointment(@Valid @RequestBody AppointmentDTO appointmentDTO) {
        // Validate date range
        if (appointmentDTO.getEndDateTime().isBefore(appointmentDTO.getStartDateTime()) ||
            appointmentDTO.getEndDateTime().isEqual(appointmentDTO.getStartDateTime())) {
            throw new IllegalArgumentException("End date time must be after start date time");
        }

        // Create new appointment entity from DTO
        Appointment appointment = new Appointment();

        // Load and set patient
        if (appointmentDTO.getPatientId() != null) {
            User patient = userRepository.findById(appointmentDTO.getPatientId().toString())
                    .orElseThrow(() -> new ResourceNotFoundException("Patient not found with id: " + appointmentDTO.getPatientId()));
            appointment.setPatient(patient);
        }

        // Load and set doctor
        if (appointmentDTO.getDoctorId() != null) {
            User doctor = userRepository.findById(appointmentDTO.getDoctorId().toString())
                    .orElseThrow(() -> new ResourceNotFoundException("Doctor not found with id: " + appointmentDTO.getDoctorId()));
            appointment.setDoctor(doctor);
        }

        // Load and set caregiver (optional)
        if (appointmentDTO.getCaregiverId() != null) {
            User caregiver = userRepository.findById(appointmentDTO.getCaregiverId().toString())
                    .orElseThrow(() -> new ResourceNotFoundException("Caregiver not found with id: " + appointmentDTO.getCaregiverId()));
            appointment.setCaregiver(caregiver);
        }

        // Load and set consultation type
        if (appointmentDTO.getConsultationTypeId() != null) {
            ConsultationType consultationType = consultationTypeRepository.findById(appointmentDTO.getConsultationTypeId())
                    .orElseThrow(() -> new ResourceNotFoundException("Consultation type not found with id: " + appointmentDTO.getConsultationTypeId()));
            appointment.setConsultationType(consultationType);
        }

        // Set other fields
        appointment.setStartDateTime(appointmentDTO.getStartDateTime());
        appointment.setEndDateTime(appointmentDTO.getEndDateTime());
        appointment.setStatus(appointmentDTO.getStatus());
        appointment.setCaregiverPresence(appointmentDTO.getCaregiverPresence());
        appointment.setVideoLink(appointmentDTO.getVideoLink());
        appointment.setRecurring(appointmentDTO.isRecurring());
        appointment.setRecurrencePattern(appointmentDTO.getRecurrencePattern());
        appointment.setSimpleSummary(appointmentDTO.getSimpleSummary());

        // Set default values
        appointment.setDoctorNotes(null); // Will be updated later by doctor
        appointment.setConfirmationDatePatient(null);
        appointment.setConfirmationDateCaregiver(null);

        Appointment createdAppointment = appointmentService.createAppointment(appointment);
        return new ResponseEntity<>(convertToDTO(createdAppointment), HttpStatus.CREATED);
    }

